impl<R: NotificationPreferenceProjectionRepository> NotificationPreferenceEventHandler for NotificationPreferenceProjector<R> {

    async fn on_created(&self, event: NotificationPreferenceCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = NotificationPreferenceProjection::new(
            event.id,
            event.user_id,
            event.notification_type,
            event.channel_enabled,
            event.channels,
            event.quiet_hours_start,
            event.quiet_hours_end,
            event.quiet_timezone,
            event.digest_enabled,
            event.digest_frequency,
            event.enabled,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: NotificationPreferenceUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.notification_type = event.notification_type;
            projection.channel_enabled = event.channel_enabled;
            projection.channels = event.channels;
            projection.quiet_hours_start = event.quiet_hours_start;
            projection.quiet_hours_end = event.quiet_hours_end;
            projection.quiet_timezone = event.quiet_timezone;
            projection.digest_enabled = event.digest_enabled;
            projection.digest_frequency = event.digest_frequency;
            projection.enabled = event.enabled;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: NotificationPreferenceDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

